fn truncate_str(s: &str, max_chars: usize) -> (String, bool) {
    let mut char_count = 0;
    for (byte_idx, _) in s.char_indices() {
        char_count += 1;
        if char_count > max_chars {
            return (s[..byte_idx].to_string(), true);
